function dijkstra(src, adj) {
    const dist = new Array(adj.length).fill(Infinity);
    dist[src] = 0;
    const pq = [[0, src]];

    while (pq.length > 0) {
        const [d, u] = pq.shift();
        if (d !== dist[u]) continue;
        for (const [v, w] of adj[u]) {
            if (d + w < dist[v]) {
                dist[v] = d + w;
                pq.push([dist[v], v]);
                pq.sort((a, b) => a[0] - b[0]);
            }
        }
    }

    return dist;
}

function minWeightSubgraph(n, edges, src1, src2, dest) {
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    const dist1 = dijkstra(src1, adj);
    const dist2 = dijkstra(src2, adj);

    let res = dist1[dest] + dist2[dest];
    for (const [u, v, w] of edges) {
        res = Math.min(res, dist1[u] + dist2[v] + w);
        res = Math.min(res, dist1[v] + dist2[u] + w);
    }

    return res === Infinity ? -1 : res;
}
```

    1. Create an adjacency list representing the given graph.
2. Define a Dijkstra's algorithm function to find the shortest distance between two nodes.
3. Use Dijkstra's algorithm to find the shortest distances from `src1` and `src2` to all other nodes in the graph.
4. Initialize `res` as the sum of the shortest path distances from `src1` and `src2` to the `dest`.
5. Iterate through all edges in the graph, and for each edge, update `res` as the minimum of the following:
   a. The current value of `res`.
   b. The sum of the shortest path distances from `src1` and `src2` to one node of the edge, plus the edge weight.
   c. The sum of the shortest path distances from `src2` and `src1` to one node of the edge, plus the edge weight.
6. If `res` is unchanged, return -1; otherwise, return the minimum weight subgraph.

