import java.util.*;

public int minWeightSubgraph(int n, int[][] edges, int src1, int src2, int dest) {
    List<List<int[]>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        adj.add(new ArrayList<>());
    }
    for (int[] edge : edges) {
        adj.get(edge[0]).add(new int[]{edge[1], edge[2]});
    }

    IntFunction<int[]> dijkstra = src -> {
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, src});

        while (!pq.isEmpty()) {
            int[] top = pq.poll();
            int d = top[0], u = top[1];
            if (d != dist[u]) continue;
            for (int[] nei : adj.get(u)) {
                int v = nei[0], w = nei[1];
                if (d + w < dist[v]) {
                    dist[v] = d + w;
                    pq.offer(new int[]{dist[v], v});
                }
            }
        }

        return dist;
    };

    int[] dist1 = dijkstra.apply(src1);
    int[] dist2 = dijkstra.apply(src2);

    int res = dist1[dest] + dist2[dest];
    for (int[] edge : edges) {
        int u = edge[0], v = edge[1], w = edge[2];
        res = Math.min(res, dist1[u] + dist2[v] + w);
        res = Math.min(res, dist1[v] + dist2[u] + w);
    }

    return res == Integer.MAX_VALUE ? -1 : res;
}
```

